1	export interface Item {
2	  type: string;
3	}
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 1.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const COMPONENT_BUNDLE_BASE = 60;
18	const COMPONENT_BUNDLE_SIZE = 3;
19	const BUNDLEABLE_COMPONENTS = new Set(["rune"]);
20	
21	function roundUpToWholeG(amount: number): number {
22	  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
23	  return Math.ceil(Math.round(amount * 100) / 100);
24	}
25	
26	function premiumFor(item: Item): number {
27	  const basePremium = BASE_PREMIUMS[item.type];
28	  return roundUpToWholeG(basePremium * FIRST_INSURANCE_SURCHARGE);
29	}
30	
31	function isThreeAlikeBundle(items: Item[]): boolean {
32	  return (
33	    items.length === COMPONENT_BUNDLE_SIZE &&
34	    BUNDLEABLE_COMPONENTS.has(items[0].type) &&
35	    items.every((item) => item.type === items[0].type)
36	  );
37	}
38	
39	function bundlePremium(): number {
40	  return roundUpToWholeG(COMPONENT_BUNDLE_BASE * FIRST_INSURANCE_SURCHARGE);
41	}
42	
43	export function quote(
44	  _customer: { yearsWithMHPCO: number },
45	  items: Item[],
46	  _previousContracts?: number,
47	): number {
48	  const itemsTotal = isThreeAlikeBundle(items)
49	    ? bundlePremium()
50	    : items.reduce((sum, item) => sum + premiumFor(item), 0);
51	  return itemsTotal + PROCESSING_FEE;
52	}
53	
54	export function claim(): number {
55	  return undefined as unknown as number;
56	}
